Or you could use `__getattr__()` instead of `__getattribute__()`:
```python
    def __getattr__(self, name):
        subproc = object.__getattribute__(self, '__subproc')
        return getattr(subproc, name)
```

You don't need to remember the handle. Instead, you should remember the **end time**. The following class should work fine.

```python
class PomodoroHandler(telepot.helper.ChatHandler):
    def __init___(self, seed_tuple, timeout):
        super(PomodoroHandler, self).__init__(seed_tuple, timeout)
        self._endtime = None

    @asyncio.coroutine
    def on_message(self, msg):
        if "/pomodorostart" in msg["text"]:
            yield from self.pomodoro_begin(msg)
        if "/timeleft" in msg["text"]:
            yield from self.pomodoro_time_left(msg)

    @asyncio.coroutine
    def pomodoro_time_left(self, msg):
        yield from self.sender.sendMessage('%.2f' % (self._endtime - time.time()))

    @asyncio.coroutine
    def pomodoro_end(self, msg):
        yield from self.sender.sendMessage("POMODORO END!")

    @asyncio.coroutine
    def pomodoro_begin(self, msg):
        h = asyncio.get_event_loop().call_later(
            20,
            lambda: asyncio.async(self.pomodoro_end(msg)))
        self._endtime = time.time() + 20

        yield from self.sender.sendMessage("POMODORO BEGIN!")
```

Here is some generic code to get the intermediate certificates from the output of acme-tiny.py

```py
#!/usr/bin/env python2
# vim:fileencoding=utf-8
# License: GPLv3 Copyright: 2015, Kovid Goyal <kovid at kovidgoyal.net>

from __future__ import (unicode_literals, division, absolute_import,
                        print_function)
import subprocess, codecs, locale, shlex, re, sys
try:
    from urllib2 import urlopen
except ImportError:
    from urllib.request import urlopen

OPENSSL = 'openssl'

def log(*args, **kw):
    kw['file'] = sys.stderr
    print(*args, **kw)
    sys.stderr.flush()

try:
    ENCODING = locale.getpreferredencoding() or 'utf-8'
    if codecs.lookup(ENCODING).name == 'ascii':
        ENCODING = 'utf-8'
except Exception:
    ENCODING = 'utf-8'

def openssl(cmd, err_msg, stdin=None, decode=True, err_class=SystemExit):
    if isinstance(cmd, type('')):
        cmd = shlex.split(cmd)
    if isinstance(stdin, type('')):
        stdin = stdin.encode(ENCODING)
    proc = subprocess.Popen(
        [OPENSSL] + cmd, stdin=subprocess.PIPE if stdin else None,
        stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    out, stderr = proc.communicate(stdin)
    if proc.returncode != 0:
        if err_class is SystemExit:
            print(stderr)
        raise err_class(err_msg)
    return out.decode(ENCODING) if decode else out

def cert_as_pem(encoded_cert):
    for cert_type in ('x509', 'pkcs7 -print_certs'):
        for encoding in 'PEM DER'.split():
            cmd = cert_type + ' -inform ' + encoding + ' -outform PEM'
            try:
                val = openssl(cmd, 'Failed to convert certificate to PEM format', stdin=encoded_cert, err_class=ValueError)
                m = re.search(r'^-+', val, flags=re.MULTILINE)
                if m is not None:
                    val = val[m.start():]
                return val
            except ValueError:
                pass
    raise Exception('Could not decode certificate')

def get_issuer_url(encoded_cert):
    cert = openssl('x509 -inform PEM -noout -text', 'Failed to parse certificate', encoded_cert)
    m = re.search(r'^\s*CA Issuers - URI:(.+)$', cert, flags=re.MULTILINE)
    if m is not None:
        return m.group(1)

def main():
    certs = []
    cert = cert_as_pem(sys.stdin.read())
    certs.append(cert)
    while True:
        iurl = get_issuer_url(cert)
        if iurl is None:
            break
        log('Getting issuer certificate:', iurl)
        cert = cert_as_pem(urlopen(iurl).read())
        certs.append(cert)
    if len(certs) > 1:
        certs.pop()  # We dont want the anchor certificate, only intermediates and leaf
    sys.stdout.write(('\n'.join(certs)).encode(ENCODING))

if __name__ == '__main__':
    main()
```

Save it to a file named get-intermediate-certs and run it

