get-intermediate-certs < cert-from-acme-tiny > cert-bundle

Then change nginx to use cert-bundle as the certificate instead of cert-from-acme-tiny

The stated problem can be created by the following steps:
1. Start a Kafka server, say the port is 51147, and create a topic, say "APP"
2. Create 2 KafkaConsumers, one in Java and one in Python:
Java: 
```
import java.util.ArrayList;
import java.util.List;
import java.util.Properties;
import org.apache.kafka.clients.consumer.ConsumerConfig;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.ConsumerRecords;
import org.apache.kafka.clients.consumer.KafkaConsumer;
import org.apache.kafka.common.KafkaException;
import org.apache.kafka.common.TopicPartition;
import org.apache.kafka.common.serialization.ByteArrayDeserializer;
import org.apache.kafka.common.serialization.StringDeserializer;
public final class JavaTest
{
    public static void main(final String[] args)
    {
        final String topic = "APP";
        final List<TopicPartition> partitions = new ArrayList<>();
        partitions.add(new TopicPartition(topic, 0));
        String kafkaConnectionString = "localhost:51147";
        final Properties props = new Properties();
        props.put(ConsumerConfig.AUTO_COMMIT_INTERVAL_MS_CONFIG, String.valueOf(5000));
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, kafkaConnectionString);
        props.put(ConsumerConfig.GROUP_ID_CONFIG, "ZEN");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
        props.put(ConsumerConfig.SESSION_TIMEOUT_MS_CONFIG,String.valueOf(10000));
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, ByteArrayDeserializer.class.getName());
        final KafkaConsumer<byte[], byte[]> kafkaConsumer = new KafkaConsumer<>(props);
        kafkaConsumer.assign(partitions);
        final ConsumerRecords<byte[], byte[]> consumerRecords;
        try
        {
            consumerRecords = kafkaConsumer.poll(10000);
        }
        catch (final KafkaException ex)
        {
            System.err.println(String.format(
                "failed to receive records from the '%s' topic from the Kafka server at '%s', " +
                    "details: %s", topic, kafkaConnectionString, ex.getMessage()));
            return;
        }
        System.out.println(String.format(
            "received %d records from the '%s' topic from the Kafka server at '%s'",
            consumerRecords.count(), topic, kafkaConnectionString));
    }
}
```
Python: 
```
from kafka import KafkaConsumer
consumer = KafkaConsumer(bootstrap_servers=["localhost:51147"], group_id="ZEN")
consumer.assign([TopicPartition("APP", 0)])
consumer.poll(timeout_ms=10000)
```
3. After running the 2 consumers, kill the Kafka server process (before 10 secs poll timeout)

Java consumer returns from the poll after timeout but the Python consumer gets stuck.

