You will have to make it more resilient to fact that ``__doc__`` may not exist or could return ``None``, but you could use:

```
import wrapt

def mydec(wrapped):
    @wrapt.decorator
    def wrapper(wrapped, instance, args, kwargs):
        """
        docs for decorator

        """

        return wrapped(*args, **kwargs)

    decorated = wrapper(wrapped)

    wrapt.FunctionWrapper.__setattr__(decorated, "__doc__",
            wrapped.__doc__ + wrapper.__doc__)

    return decorated

@mydec
def function():
    """docs for function"""

print(help(function))
```

