#include "stdafx.h"
#include <windows.h>
#include <winscard.h>
#include <iostream>
#include <WinBase.h>
#include <string>

#define IOCTL_CCID_ESCAPE SCARD_CTL_CODE(3500)
using namespace std;

int main(int argc, char * argv[])
{
	const BYTE ESCAPE_COMMAND_TEST[] = { 0xA0, 0xBE };
	SCARDCONTEXT hContext;
	SCARDHANDLE hCard;
	DWORD dwProtocol;
	BYTE abResponse[256];
	DWORD dwRespLen = NULL;
	LONG rc = 0;
	LPTSTR          pmszReaders = NULL;
	LPTSTR          pReader;
	LPTSTR          pfirstReader = NULL;
	LONG            lReturn, lReturn2;
	DWORD           cch = SCARD_AUTOALLOCATE;

	/* Instanciate the winscard.dll library */
	rc = SCardEstablishContext(SCARD_SCOPE_SYSTEM, NULL, NULL, &hContext);
	if (rc != SCARD_S_SUCCESS) {
		cout << "Could not get context! (SCardEstablishContext)" << endl;
		return -1;
	}

	// Retrieve the list the readers.
	lReturn = SCardListReaders(hContext,
		SCARD_DEFAULT_READERS,
		(LPTSTR)&pmszReaders,
		&cch);

	switch (lReturn)
	{
	case SCARD_E_NO_READERS_AVAILABLE:
		cout << "No readers connected! (SCARD_E_NO_READERS_AVAILABLE)" << endl;
		return -2;
		break;

	case SCARD_S_SUCCESS:
	{
		// Do something with the multi string of readers.
		// Output the values.
		// A double-null terminates the list of values.
		pReader = pmszReaders;
		while ('\0' != *pReader)
		{
			// Display the value.
			printf("Reader found: '%S'\n", pReader);
			if (pfirstReader == NULL)
				pfirstReader = pReader;
			// Advance to the next value.
			pReader = pReader + wcslen((wchar_t *)pReader) + 1;
		}

		rc = SCardConnect(hContext, pfirstReader, SCARD_SHARE_DIRECT, 0, &hCard, &dwProtocol);
		if (rc != SCARD_S_SUCCESS) {
			cout << "Could not connect to reader! (SCardConnect)" << endl;
			return -3;
		}

		std::cout << "Successfully connected to reader!" << std::endl;

		rc = SCardControl(hCard, IOCTL_CCID_ESCAPE, ESCAPE_COMMAND_TEST, sizeof(ESCAPE_COMMAND_TEST), abResponse, sizeof(abResponse), &dwRespLen);
		if (rc != SCARD_S_SUCCESS) {
			cout << "Control command sending failed (SCardControl)!" << endl;
			exit(-4);
		}

		SCardDisconnect(hCard, SCARD_LEAVE_CARD);
		// Free the memory.
		lReturn2 = SCardFreeMemory(hContext,
			pfirstReader);
		if (SCARD_S_SUCCESS != lReturn2)
			printf("Failed SCardFreeMemory\n");
		SCardReleaseContext(hContext);
		std::cout << "Reader successfully disconnected." << std::endl;
	}
	break;
	default:
		printf("Failed SCardListReaders\n");
		return -3;
		break;
	}
	return 0;
}
```

@georgreen it sounds like you're not running your flask app in a gevent container. You need to use a gevent container such as gnicorn. Easiest to get started is to use the built-in gevent.wsgi module, like so

```
from flask import Flask, request
from gevent.wsgi import WSGIServer
import flask_sse

app = Flask(__name__)
channel = flask_sse.Channel()

@app.route('/subscribe')
def subscribe():
	return channel.subscribe()

@app.route('/publish', methods=['POST'])
def publish():
	channel.publish(request.data)
	return "OK"

@app.route('/')
def index():
	return """<body><script>
var eventSource = new EventSource('/subscribe');
eventSource.onmessage = function(m) {
	console.log(m);
	var el = document.getElementById('messages');
	el.innerHTML += m.data;
	el.innerHTML += "</br>";
}
function post(url, data) {
	var request = new XMLHttpRequest();
	request.open('POST', url, true);
	request.setRequestHeader('Content-Type', 'text/plain; charset=UTF-8');
	request.send(data);
}
function publish() {
	var message = document.getElementById("msg").value;
	post('/publish', message);
}
</script>
<input type="text" id="msg">
<button onclick="publish()">send</button>
<p id="messages"></p>
</body>"""

def main():
	server = WSGIServer(("", 5000), app)
	server.serve_forever()

if __name__ == "__main__":
	main()
```

This app you should be able to run directly. :-) The "flask_sse" is the code I pasted above. Good luck.

